var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_QM","text":{"KOREA":"사장님…! 사장님……!","JPN":"社長……！　社長……！","ENG":"Boss...! Boss...!","TWN":"老闆…！老闆……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_QM","text":{"KOREA":"정신 차려! 젠장, 눈 좀 떠 보라고……!","JPN":"しっかりして！　くそ……目、覚ましてよ……！","ENG":"Snap out of it! C'mon, open your eyes...!","TWN":"你醒醒！該死，睜開眼睛……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"미나 양……?","JPN":"ミナ君……？","ENG":"Mina...?","TWN":"米娜……？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사장님? 괜찮아…? 정신이 좀 들어……?","JPN":"社長？　大丈夫……？　気がついた？","ENG":"Boss? You okay...? Can you tell where you are...?","TWN":"老闆？你沒事吧…？意識還清楚嗎…？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하아, 다행이다. 난 또 사장님이 어떻게 되는 줄 알고…….","JPN":"はあ、よかった。社長に何かあったらと思って……","ENG":"Whew, thank goodness. I thought something had really happened to you...","TWN":"呼，太險。我怕老闆又出什麼事……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 날 감싸준 건가?","JPN":"君がかばってくれたのか？","ENG":"Did you take care of me?","TWN":"是你護住我的嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거 고맙군. 병원 신세 진지 얼마 지나지도 않는데, 하마터면 또 입원할 뻔했어.","JPN":"すまないな。退院したばかりだというのに、また入院させてしまうところだった。","ENG":"Thanks. I'd barely left the hospital and almost ended up back inside.","TWN":"謝謝你。才剛出院，差點又要進醫院了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"감사 인사를 하려면, 노엘한테 해.","JPN":"お礼はノエルに言って。","ENG":"If you're thanking anyone, thank Noelle.","TWN":"要道謝的話，就去找洛艾兒吧。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘이 요격해 주지 않았다면, 우리 둘 다 커다란 잔해 속에 파묻혔을 테니까.","JPN":"私たちが巨大な瓦礫に埋もれずにすんだのは、ノエルが迎撃してくれたおかげだから。","ENG":"If she hadn't intercepted it, we'd both be buried in rubble.","TWN":"如果不是洛艾兒出手，我們兩個都會被埋在巨大的殘骸中。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"카운터인 나는 괜찮다고 해도, 사장님은 아니잖아?","JPN":"カウンターの私はともかく、社長はそうなったら危ないでしょ？","ENG":"I'm a Counter, so I'd survive. But you wouldn't have.","TWN":"我是制裁者還好，但老闆你又不是。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 그렇군.","JPN":"そうだな。","ENG":"That's true.","TWN":"……那倒是。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 미나 양… 우리 지금 너무 가까운 거 같네만……?","JPN":"それよりミナ君……距離が近すぎないか……？","ENG":"Still, Mina... We're awfully close right now...","TWN":"不過米娜……我們現在是不是靠得太近了……？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이러다가 누가 이 모습을 보기라도 하면…….","JPN":"誰かに見られでもしたら……","ENG":"If someone saw us like this...","TWN":"要是被人看到……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음……?","JPN":"うん……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아앗! 무슨 생각을 하는 거야, 이런 상황에서!","JPN":"あ、ああっ！　何考えてるんだよ、こんな状況で！","ENG":"W-what are you even thinking about at a time like this?!","TWN":"啊啊！這種情況下你還在想什麼呢！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쩔 수 없잖아! 이건 사장님을 구하려다가……","JPN":"だって仕方ないでしょ！　これは社長を助けようとして……","ENG":"I didn't have a choice! I was trying to save you—","TWN":"又不是故意的！這都是為了救老闆……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음!?","JPN":"っ！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배! 사장님! 두 분 다 괜찮으세요……","JPN":"ミナ先輩！　社長！　二人ともご無事で……","ENG":"Mina! Boss! Are you both all ri–","TWN":"米娜前輩！老闆！你們都沒事吧……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헉!?","JPN":"はっ！？","ENG":"Eek?!","TWN":"嗯？!"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"충격! 미나 선배의 공격적인 어프로치……!?","JPN":"ショック！　ミナ先輩のアグレッシブなアプローチ……！？","ENG":"Shocking! Mina going in with bold moves...?!","TWN":"震驚！米娜前輩帶有攻擊性的接近……！？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요…! 짐작은 하고 있었지만, 어쩌면 미나 선배와 사장님은 사실 그렇고 그런……!","JPN":"そうだったんですね……！　そんな気はしていましたが、ミナ先輩と社長は実はそういう関係……！","ENG":"So it's true...! I suspected, but maybe you two really are–!","TWN":"原來如此…！雖然我早就猜想過，但沒想到米娜前輩和老闆其實是那種關係……！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 헛소리야!","JPN":"バカなこと言うんじゃないよ！","ENG":"Nonsense!","TWN":"說什麼呢！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저, 저는 괜찮아요! 선배도 사장님도 둘 다 좋으니까!","JPN":"わ、私は平気ですよ！　先輩も社長も好きだから！","ENG":"It's fine! I like both of you, so I'm okay with it!","TWN":"不，不用在乎我！前輩和老闆的話我可以接受！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 생각하는 그런 거 아니거든……!?","JPN":"あなたが思っているような関係じゃないから……！","ENG":"It's not what you think...!","TWN":"不是你想的那樣……！?"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 그렇게 멀뚱멀뚱 보고만 있지 말고 좀 도와달라고!","JPN":"それより、ぼうっと見てないで手伝ってよ！","ENG":"Instead of gawking, give me a hand here!","TWN":"別光站在那裡發呆，快來幫幫我！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 위에서 갑자기 움직이면, 사장님이 잔해에 다칠 수도 있단 말이야!","JPN":"私が急に動いたら、瓦礫で社長が怪我するかもしれない！","ENG":"If I move wrong, Boss could get crushed!","TWN":"如果我在上面突然移動，老闆可能會被碎片傷到！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엇! 잠시만요, 사장님! 금방 꺼내드릴게요!","JPN":"あっ！　ちょっよ待ってくださいね、社長！　すぐに助けます！","ENG":"Right! Hold on, Boss, I'll get you out!","TWN":"喔！等等，老闆！我馬上來幫你！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거 두 사람에게 또 신세를 지는군.","JPN":"二人にはまた世話になってしまったな。","ENG":"Once again, I owe you one.","TWN":"又要麻煩你們兩個了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};